import React, { useState, useEffect } from 'react';
import { YMaps, Map, Placemark } from '@pbe/react-yandex-maps';
import axios from 'axios'; // или используйте fetch

function TestHome() {
  const [center, setCenter] = useState([55.751574, 37.573856]);
  const [markers, setMarkers] = useState([]);
  const [loading, setLoading] = useState(true);

  // Загрузка маркеров из БД
  useEffect(() => {
    fetchMarkersFromDatabase();
  }, []);

  // Функция загрузки данных из БД
  const fetchMarkersFromDatabase = async () => {
    try {
      setLoading(true);

      // Пример запроса к вашему API
      const response = await axios.get('/api/markers');
      // Или напрямую к Firebase/PostgreSQL/MongoDB

      // Предположим, что данные приходят в формате:
      // [
      //   {
      //     id: 1,
      //     latitude: 55.751574,
      //     longitude: 37.573856,
      //     title: "Москва",
      //     description: "Столица России",
      //     type: "city",
      //     color: "#FF0000"
      //   },
      //   ...
      // ]

      setMarkers(response.data);

      // Если есть маркеры, центрируем карту на первом
      if (response.data.length > 0) {
        setCenter([response.data[0].latitude, response.data[0].longitude]);
      }

    } catch (error) {
      console.error('Ошибка загрузки маркеров:', error);
      // Запасные данные для демонстрации
      setMarkers(getDefaultMarkers());
    } finally {
      setLoading(false);
    }
  };

  // Создание SVG иконки с цветом из БД
  const createMarkerIcon = (color = '#FF0000', type = 'default') => {
    let svg;

    switch(type) {
      case 'city':
        svg = `<svg width="40" height="40" viewBox="0 0 40 40" xmlns="http://www.w3.org/2000/svg">
          <circle cx="20" cy="20" r="15" fill="${color}" opacity="0.8"/>
          <circle cx="20" cy="20" r="8" fill="white"/>
        </svg>`;
        break;
      case 'shop':
        svg = `<svg width="40" height="40" viewBox="0 0 40 40" xmlns="http://www.w3.org/2000/svg">
          <rect x="10" y="15" width="20" height="15" rx="3" fill="${color}"/>
          <rect x="15" y="10" width="10" height="5" fill="${color}"/>
        </svg>`;
        break;
      default:
        svg = `<svg width="40" height="40" viewBox="0 0 40 40" xmlns="http://www.w3.org/2000/svg">
          <path d="M20 2C12.27 2 6 8.27 6 16C6 23.73 20 38 20 38C20 38 34 23.73 34 16C34 8.27 27.73 2 20 2Z" fill="${color}"/>
          <circle cx="20" cy="16" r="6" fill="white"/>
        </svg>`;
    }

    return `data:image/svg+xml;base64,${btoa(svg)}`;
  };

  if (loading) {
    return <div style={{ padding: '40px', textAlign: 'center' }}>Загрузка карты...</div>;
  }

  return (
    <div style={{ width: '100%', height: '600px' }}>
      <YMaps>
        <Map 
          state={{ center, zoom: 10 }} 
          width="100%" 
          height="100%"
        >
          {markers.map((marker) => (
            <Placemark
              key={marker.id}
              geometry={[marker.latitude, marker.longitude]}
              options={{
                iconLayout: 'default#image',
                iconImageHref: createMarkerIcon(marker.color, marker.type),
                iconImageSize: [40, 40],
                iconImageOffset: [-20, -40],
              }}
              properties={{
                hintContent: marker.title,
                balloonContent: `
                  <div style="padding: 15px; max-width: 250px">
                    <h3 style="margin: 0 0 10px 0; color: ${marker.color}">${marker.title}</h3>
                    <p style="margin: 0 0 10px 0">${marker.description || ''}</p>
                    <div style="font-size: 12px; color: #666">
                      Координаты:<br/>
                      ${marker.latitude.toFixed(6)}, ${marker.longitude.toFixed(6)}
                    </div>
                    ${marker.address ? `<div style="margin-top: 8px; font-size: 12px">${marker.address}</div>` : ''}
                  </div>
                `,
              }}
            />
          ))}
        </Map>
      </YMaps>

      <div style={{ marginTop: '10px', padding: '10px', backgroundColor: '#f5f5f5', borderRadius: '5px' }}>
        <strong>Маркеров на карте:</strong> {markers.length}
      </div>
    </div>
  );
}

// Функция для демонстрационных данных
const getDefaultMarkers = () => [
  {
    id: 1,
    latitude: 55.751574,
    longitude: 37.573856,
    title: "Москва",
    description: "Столица России",
    type: "city",
    color: "#FF0000",
    address: "Красная площадь, 1"
  },
  {
    id: 2,
    latitude: 59.934280,
    longitude: 30.335098,
    title: "Санкт-Петербург",
    description: "Северная столица",
    type: "city",
    color: "#0000FF",
    address: "Дворцовая площадь"
  },
  {
    id: 3,
    latitude: 56.326887,
    longitude: 44.005986,
    title: "Нижний Новгород",
    description: "Город на Волге",
    type: "city",
    color: "#00AA00",
    address: "Кремль"
  }
];

export default TestHome;
